" Classic SE11 Database View (legacy)
" SE11: View Type = Database View
" INNER JOIN only, no annotations

" Modern CDS View (S/4HANA standard)
@AbapCatalog.sqlViewName: 'ZCDS_SO_CUST'
@OData.publish: true
define view ZCDS_SalesOrder_Customer as
  select from vbak as so
    inner join kna1 as c on so.kunnr = c.kunnr
  { so.vbeln, so.kunnr, c.name1, so.netwr }
